import { useState } from "react";

export default function Card({value,type}){
try{
    const[res,setres]=useState("");
    const[ip,setip]=useState("");

    const sendmessage=async ()=>{
        console.log("sendmessage is working:",ip);
        let r=await fetch(`${process.env.REACT_APP_BACKEND_URL}chat${type}`,{
        method:"POST",
        headers:{
            "Content-Type":"application/json",
        },
        body:JSON.stringify({message:ip})}
        );
        setres(await r.json());
    }

    return(
    <>
    <div className="card">{value}</div>
    <input value={ip} onChange={(e)=>{setip(e.target.value)}} placeholder="Enter Your Question Child" />

    <button onClick={sendmessage}>Send</button>

    <div className="chatbot">{res}</div>
    </>
    );
}catch(e){
    console.log(e.message);}
}
